import{j as l,D as n,b as e,c as i,a2 as r,g as h,h as a,f as d,G as s,a3 as A}from"./chunks/framework.BDRKwY9B.js";const f=JSON.parse('{"title":"","description":"","frontmatter":{"layout":"home","hero":{"name":"AuroraBot","text":"新一代内驱式、自主决策的智能体框架","tagline":"四层解耦架构 · 有向有环图认知 Agent 网络 · 统一联合记忆","image":{"src":"/logo.svg","alt":"AuroraBot Logo"},"actions":[{"theme":"brand","text":"自我介绍","link":"/start/overview.html"},{"theme":"alt","text":"快速开始","link":"/start/getting-started.html"},{"theme":"alt","text":"四层架构","link":"/architecture/system-overview.html"},{"theme":"alt","text":"应用开发","link":"/develop/app-development.html"}]},"features":[{"icon":"🧠","title":"文件驱动认知拓扑","details":"代号 CortexForge——Node / Agent / Router 节点通过文件篮 + 事件总线协作, 静态依赖图 + 动态波前, 自然形成持续认知循环."},{"icon":"📔","title":"统一联合记忆","details":"图式事实记忆、情景记忆与知识图谱经验记忆借助 mem0 融合, 覆盖所有认知活动, 关联式演化而非线性记录."},{"icon":"🤖","title":"统一模型网关","details":"Brain 层统一管理 LLM 与 Embedding 调用, 优化配额与重试, 节点无需感知模型细节."},{"icon":"🧩","title":"App 插件体系","details":"每个 App 都是独立的感知器与执行器, 通过统一 PlatformAPI 与宿主交互. 高度解耦, 按需插拔."},{"icon":"🔌","title":"MCP 协议适配","details":"任意 MCP 服务器都可以以 App 形态接入, 工具能力自动映射为内核可调用的命令."},{"icon":"📖","title":"文档驱动开发","details":"随提交更新的项目的文档站, 保证文档与代码同步更新, 让开发更省心."}]},"headers":[],"relativePath":"index.md","filePath":"index.md","lastUpdated":1778837174000}'),p={name:"index.md"};function b(g,t,m,u,E,B){const o=n("Mermaid");return e(),i("div",null,[t[1]||(t[1]=r('<h2 id="她是什么" tabindex="-1">她是什么 <a class="header-anchor" href="#她是什么" aria-label="Permalink to &quot;她是什么&quot;">​</a></h2><p>AuroraBot 是新一代<strong>内驱式、自主决策的智能体框架</strong>。</p><p>她由四层协作者构成：</p><ul><li><strong>应用层（Apps）</strong> — 可插拔的感知器与执行器，通过统一 PlatformAPI 接入外部世界</li><li><strong>平台层（Platform）</strong> — 统一管理应用的运行时宿主，负责与上下层双向通信</li><li><strong>内核层（Kernel）</strong> — 管理与调度核心，编排事件流与命令流</li><li><strong>认知层（Brain）</strong> — 文件驱动的认知操作系统内核。Node / Agent / Router 节点网络 + 事件总线 + 统一 LLM 网关 + 统一联合记忆</li></ul><blockquote><p>她不是在“等待指令”，而是在“持续观察、自主决策、主动行动”。</p></blockquote><h2 id="四层架构" tabindex="-1">四层架构 <a class="header-anchor" href="#四层架构" aria-label="Permalink to &quot;四层架构&quot;">​</a></h2>',6)),(e(),h(A,null,{default:a(()=>[s(o,{id:"mermaid-39",class:"mermaid",graph:"flowchart%20LR%0A%20%20%20%20subgraph%20APPS%5B%22%E5%BA%94%E7%94%A8%E5%B1%82%20(Apps)%22%5D%0A%20%20%20%20%20%20%20%20QQ%5B%22QQ%20%E6%8E%A5%E5%85%A5%22%5D%0A%20%20%20%20%20%20%20%20ALARM%5B%22%E5%AE%9A%E6%97%B6%E6%8F%90%E9%86%92%22%5D%0A%20%20%20%20%20%20%20%20DIARY%5B%22%E6%97%A5%E8%AE%B0%22%5D%0A%20%20%20%20end%0A%0A%20%20%20%20subgraph%20PLATFORM%5B%22%E5%B9%B3%E5%8F%B0%E5%B1%82%20(Platform)%22%5D%0A%20%20%20%20%20%20%20%20EVENTS%5B%22%E4%BA%8B%E4%BB%B6%E9%98%9F%E5%88%97%22%5D%0A%20%20%20%20%20%20%20%20CMDS%5B%22%E5%91%BD%E4%BB%A4%E6%B3%A8%E5%86%8C%22%5D%0A%20%20%20%20end%0A%0A%20%20%20%20subgraph%20KERNEL%5B%22%E5%86%85%E6%A0%B8%E5%B1%82%20(Kernel)%22%5D%0A%20%20%20%20%20%20%20%20SCHEDULER%5B%22%E5%BF%83%E8%B7%B3%E8%B0%83%E5%BA%A6%E5%99%A8%22%5D%0A%20%20%20%20end%0A%0A%20%20%20%20subgraph%20BRAIN%5B%22%E8%AE%A4%E7%9F%A5%E5%B1%82%20(Brain)%22%5D%0A%20%20%20%20%20%20%20%20direction%20LR%0A%20%20%20%20%20%20%20%20NODES%5B%22Agent%20%E8%8A%82%E7%82%B9%20(%E6%9C%89%E5%90%91%E6%9C%89%E7%8E%AF%E5%9B%BE)%22%5D%0A%20%20%20%20%20%20%20%20GATEWAY%5B%22LLM%20%2F%20Embedding%20%E7%BD%91%E5%85%B3%22%5D%0A%20%20%20%20%20%20%20%20MEMORY%5B%22%E7%BB%9F%E4%B8%80%E8%81%94%E5%90%88%E8%AE%B0%E5%BF%86%22%5D%0A%20%20%20%20end%0A%0A%20%20%20%20APPS%20%3C--%3E%7C%22AppEvent%20%2F%20invoke_command%22%7C%20PLATFORM%0A%20%20%20%20PLATFORM%20%3C--%3E%7C%22%E4%BA%8B%E4%BB%B6%20%2F%20%E5%91%BD%E4%BB%A4%22%7C%20KERNEL%0A%20%20%20%20KERNEL%20%3C--%3E%7C%22%E8%B0%83%E5%BA%A6%20%2F%20%E7%8A%B6%E6%80%81%22%7C%20BRAIN%0A"})]),fallback:a(()=>[...t[0]||(t[0]=[d(" Loading... ",-1)])]),_:1})),t[2]||(t[2]=r('<h3 id="高度解耦的-app-插件体系" tabindex="-1">高度解耦的 App 插件体系 <a class="header-anchor" href="#高度解耦的-app-插件体系" aria-label="Permalink to &quot;高度解耦的 App 插件体系&quot;">​</a></h3><p>每个 App 都是独立的感知器与执行器，通过统一的 <code>PlatformAPI</code> 与宿主交互。接入 QQ、定时器、文件系统、甚至外部 API——都只需要一个 App。</p><h3 id="有向有环图的认知-agent-网络" tabindex="-1">有向有环图的认知 Agent 网络 <a class="header-anchor" href="#有向有环图的认知-agent-网络" aria-label="Permalink to &quot;有向有环图的认知 Agent 网络&quot;">​</a></h3><p>认知不依赖单一“超级 Agent”，而是由多个 Agent / Router 节点构成有向有环图。节点之间通过文件篮机制传递状态，形成持续运转的认知循环。未来开放认知节点插件，供第三方扩展认知能力。</p><h3 id="统一联合记忆" tabindex="-1">统一联合记忆 <a class="header-anchor" href="#统一联合记忆" aria-label="Permalink to &quot;统一联合记忆&quot;">​</a></h3><p>AuroraBot 的记忆不只是“存下来”，而是<strong>结构化地生长</strong>。知识图谱、向量检索与情景记忆融合为一个统一记忆层，让每一次事件、每一次决策都参与记忆演化。</p><h2 id="计划中的-mcp-适配容器" tabindex="-1">计划中的 MCP 适配容器 <a class="header-anchor" href="#计划中的-mcp-适配容器" aria-label="Permalink to &quot;计划中的 MCP 适配容器&quot;">​</a></h2><p>我们正在设计一个 <strong>MCP (Model Context Protocol) 适配容器</strong>，让任意 MCP 服务器以 App 形态接入 AuroraBot。</p><p>这意味着：</p><ul><li>任何遵循 MCP 协议的工具都可以成为 AuroraBot 的能力延伸</li><li>MCP 工具会被自动映射为内核可调用的命令</li><li>内核无需感知 MCP 协议细节，由适配容器统一处理</li></ul><blockquote><p>让 MCP 生态成为你的能力延伸。</p></blockquote><h2 id="快速导航" tabindex="-1">快速导航 <a class="header-anchor" href="#快速导航" aria-label="Permalink to &quot;快速导航&quot;">​</a></h2><p>完整的架构设计、使用指南与开发文档请 <strong><a href="https://jufirex.github.io/AuroraBot/" target="_blank" rel="noreferrer">访问 AuroraBot 文档站 📖</a></strong>：</p><table tabindex="0"><thead><tr><th>文档</th><th>说明</th></tr></thead><tbody><tr><td><a href="https://jufirex.github.io/AuroraBot/start/overview.html" target="_blank" rel="noreferrer">项目总览</a></td><td>快速了解 AuroraBot 的定位与四层分层</td></tr><tr><td><a href="https://jufirex.github.io/AuroraBot/start/getting-started.html" target="_blank" rel="noreferrer">快速开始</a></td><td>从零把项目跑起来</td></tr><tr><td><a href="https://jufirex.github.io/AuroraBot/architecture/system-overview.html" target="_blank" rel="noreferrer">系统架构总览</a></td><td>理解 Apps / Platform / Kernel / Brain 四层</td></tr><tr><td><a href="https://jufirex.github.io/AuroraBot/architecture/brain-architecture.html" target="_blank" rel="noreferrer">认知架构</a></td><td>深入有向有环图的 Agent 节点网络</td></tr><tr><td><a href="https://jufirex.github.io/AuroraBot/architecture/platform-runtime.html" target="_blank" rel="noreferrer">平台运行时</a></td><td>理解宿主与 App 的运行时关系</td></tr><tr><td><a href="https://jufirex.github.io/AuroraBot/develop/app-development.html" target="_blank" rel="noreferrer">App 开发指南</a></td><td>开发你自己的 App</td></tr><tr><td><a href="https://jufirex.github.io/AuroraBot/develop/aur-cli.html" target="_blank" rel="noreferrer">AUR CLI</a></td><td>应用开发工具链</td></tr></tbody></table><h2 id="开源致谢" tabindex="-1">开源致谢 <a class="header-anchor" href="#开源致谢" aria-label="Permalink to &quot;开源致谢&quot;">​</a></h2><p>AuroraBot 站在众多优秀开源项目的肩膀上构建：</p><table tabindex="0"><thead><tr><th>项目</th><th>说明</th><th style="text-align:left;">开源协议</th></tr></thead><tbody><tr><td><a href="https://github.com/nonebot/nonebot2" target="_blank" rel="noreferrer">NoneBot2</a></td><td>跨平台 Python 机器人框架</td><td style="text-align:left;"><a href="https://github.com/nonebot/nonebot2/blob/master/LICENSE" target="_blank" rel="noreferrer">MIT License</a></td></tr><tr><td><a href="https://github.com/BerriAI/litellm" target="_blank" rel="noreferrer">LiteLLM</a></td><td>统一 LLM API 调用层</td><td style="text-align:left;"><a href="https://github.com/BerriAI/litellm/blob/litellm_internal_staging/LICENSE" target="_blank" rel="noreferrer">LICENSE</a></td></tr><tr><td><a href="https://github.com/mem0ai/mem0" target="_blank" rel="noreferrer">mem0</a></td><td>智能体记忆基础设施</td><td style="text-align:left;"><a href="https://github.com/mem0ai/mem0/blob/main/LICENSE" target="_blank" rel="noreferrer">Apache License 2.0</a></td></tr><tr><td><a href="https://github.com/chroma-core/chroma" target="_blank" rel="noreferrer">ChromaDB</a></td><td>开源向量数据库</td><td style="text-align:left;"><a href="https://github.com/chroma-core/chroma/blob/main/LICENSE" target="_blank" rel="noreferrer">Apache License 2.0</a></td></tr><tr><td><a href="https://github.com/botuniverse/onebot" target="_blank" rel="noreferrer">OneBot</a></td><td>统一聊天机器人接口标准</td><td style="text-align:left;"><a href="https://github.com/botuniverse/onebot/blob/main/LICENSE" target="_blank" rel="noreferrer">MIT License</a></td></tr><tr><td><a href="https://github.com/vuejs/vitepress" target="_blank" rel="noreferrer">VitePress</a></td><td>文档站生成框架</td><td style="text-align:left;"><a href="https://github.com/vuejs/vitepress/blob/main/LICENSE" target="_blank" rel="noreferrer">MIT License</a></td></tr></tbody></table><p>特别感谢 <strong><a href="https://github.com/MaiM-with-u/MaiBot" target="_blank" rel="noreferrer">MaiBot</a></strong> 为本项目提供架构灵感与设计参考。</p>',18))])}const _=l(p,[["render",b]]);export{f as __pageData,_ as default};
